head.script:
scwin.dateStr = "";
scwin.rFlag = false;
scwin.sUserId = "";
scwin.sUserClsCd = "";
scwin.sClntNo = "";
scwin.sClntNm = "";
scwin.sLoUpperLobranCd = "";
scwin.oldCurPos = 0;
scwin.oldDistrictKind = "";
scwin.rtnCarInfoList = null;
scwin.rtnPosnClsCd = "";
scwin.eventYn = true;
scwin.updateYn = false;
scwin.lobranCd = "";
scwin.vehclNo = "";

scwin.eqKndCd_1 = "";
scwin.eqNrmCd_1 = "";
scwin.temp_owner_nm_1 = "";
scwin.txt_steelVehclYn = false;
scwin.direc_mgnt_yn = true;

scwin.onpageload = async function() {
    scwin.dateStr = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.sUserId = $c.ses.getUserId();
    scwin.sUserClsCd = $c.ses.getUserClsCd();
    scwin.sClntNo = $c.ses.getClntNo();
    scwin.sClntNm = $c.ses.getClntNm();
    scwin.sLoUpperLobranCd = $c.ses.getLoUpperLobranCd();

    let params = $c.data.getParameter();
    if (params != null) {
        scwin.lobranCd = (params.lobranCd == null ? "" : params.lobranCd);
        scwin.vehclNo = (params.vehclNo == null ? "" : params.vehclNo);
    }

    scwin.f_OnLoad();
};

scwin.onUdcCompleted = async function() {
};

scwin.f_OnLoad = async function() {
    scwin.direc_mgnt_yn = true;

    await scwin.f_RetrieveComboPayBaseline("OP261", "");
    await scwin.f_RetrieveSecond();
    await scwin.f_RetriveCommFltrCombo("OP108", "Y");
    await scwin.f_RetriveCommFltrCombo2("OP263", "1");
    await scwin.f_RetrieveCommonUpperCd("ds_combo_sasiKind", "ZZ210", "TL", "", "", "", "");

    $c.gus.cfDisableObjects([btn_new, btn_update, b_cancel, btn_save, btn_owner]);
    gr_EquipmentContractList.setReadOnly("grid", true);

    if (scwin.lobranCd.trim() != "") {
        co_lc_logisticsBranch.setValue(scwin.lobranCd);
        em_con_eqNo.setValue(scwin.vehclNo);
        scwin.f_Retrieve();
    }

    co_lc_logisticsBranch.setValue(scwin.sLoUpperLobranCd);

    scwin.f_districtSearchKind();
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([tbl_search]))) {
        return;
    }

    scwin.eventYn = false;

    ds_SaveEquipmentContract.removeAll();
    ds_ep_insurance.removeAll();
    ds_eqcdCtrtHistory.removeAll();

    dma_QueryCondition.set("returnVehclYn", "0");
    dma_QueryCondition.set("eqClsCd", "LV");
    dma_QueryCondition.set("eqKndCd", acb_delYn.getValue());
    dma_QueryCondition.set("ctrtBranCd", co_lc_logisticsBranch.getValue());

    let posnClsCdVal = acb_posnClsCd.getValue();
    if (posnClsCdVal == " ") {
        posnClsCdVal = "";
    }
    dma_QueryCondition.set("posnClsCd", posnClsCdVal);
    dma_QueryCondition.set("delYn", acb_vehclNo_1.getValue());

    let direcMgntYn = "0";
    if (scwin.direc_mgnt_yn) {
        direcMgntYn = "1";
    } else {
        direcMgntYn = "0";
    }
    dma_QueryCondition.set("direcMgntYn", direcMgntYn);

    let eqNoVal = em_con_eqNo.getValue();
    if (eqNoVal != null && eqNoVal != "") {
        dma_QueryCondition.set("eqCd", eqNoVal);
    } else {
        dma_QueryCondition.set("eqCd", "");
    }

    scwin.rFlag = false;
    scwin.f_RetrieveComboHwaKind("1");

    gr_EquipmentContractList.setReadOnly("grid", true);
    $c.gus.cfDisableObjects([btn_new, btn_update, b_cancel, btn_save]);

    if (co_lc_logisticsBranch.getValue() == "") {
        await $c.win.alert("배정점소를 선택해 주십시오.");
        return;
    }

    await $c.sbm.execute(sbm_RetrieveCooperationCompanyEquipmentList);
};

scwin.f_RetrieveEqcdCtrtHistory = async function() {
    let row = ds_LCCEList.getRowPosition();
    dma_QueryCondition5.set("eqCd", ds_LCCEList.getCellData(row, "eqCd"));
    await $c.sbm.execute(sbm_retrieveEqcdCtrtHistory);
};

scwin.f_CarGridAddrow = function() {
    let carKndChk_val = "LV";

    ds_SaveEquipmentContract.removeAll();
    ds_ep_insurance.removeAll();
    ds_eqcdCtrtHistory.removeAll();

    let row = ds_LCCEList.getRowPosition();
    let clntNo = "";
    let clntNm = "";
    if (row >= 0) {
        clntNo = ds_LCCEList.getCellData(row, "clntNo");
        clntNm = ds_LCCEList.getCellData(row, "clntNm");
    }

    let newRow = ds_LCCEList.insertRow();
    ds_LCCEList.setCellData(newRow, "eqClsCd", carKndChk_val);
    ds_LCCEList.setCellData(newRow, "assgnLobranCd", co_lc_logisticsBranch.getValue());
    ds_LCCEList.setCellData(newRow, "clntNo", clntNo);
    ds_LCCEList.setCellData(newRow, "clntNm", clntNm);
    ds_LCCEList.setCellData(newRow, "logisHveqRepCopCoNo", clntNo);
    ds_LCCEList.setCellData(newRow, "logisHveqRepCopCoNm", clntNm);
    ds_LCCEList.setCellData(newRow, "vehclDirecMgntYn", "1");
    ds_LCCEList.setCellData(newRow, "returnVehclYn", "0");
    ds_LCCEList.setCellData(newRow, "steelVehclYn", "0");
    ds_LCCEList.setCellData(newRow, "realPdaYn", "1");
    ds_LCCEList.setCellData(newRow, "mbssysVehclYn", "1");
    ds_LCCEList.setCellData(newRow, "lbsYn", "1");
    ds_LCCEList.setCellData(newRow, "vehclNo1", "");
    ds_LCCEList.setCellData(newRow, "vehclNo2", "");
    ds_LCCEList.setCellData(newRow, "vehclNo3", "");
    ds_LCCEList.setCellData(newRow, "vehclNo4", "");
    ds_LCCEList.setCellData(newRow, "vehclNo", "");
    ds_LCCEList.setCellData(newRow, "vehclShortCd", "");
    ds_LCCEList.setCellData(newRow, "deleteState", "2");

    co_lc_jumso_1.setSelectedIndex(0);

    scwin.f_default_LV();

    gr_EquipmentContractList.setReadOnly("grid", false);
    $c.gus.cfEnableObjects([b_cancel, btn_save]);
    $c.gus.cfDisableObjects([btn_new, btn_update]);
    txt_em_vehclNm_1.setDisabled(false);
    co_lc_jumso_1.setDisabled(false);
    txt_vehclNo_2.setDisabled(false);
    txt_vehclNo_3.setDisabled(false);
    txt_vehclNo_4.setDisabled(false);

    if (scwin.sUserId == "101384" || scwin.sUserId == "080953" || scwin.sUserId == "051390" || scwin.sUserId == "origin" || scwin.sUserId == "herekjs" || scwin.sUserId == "hpark" || scwin.sUserId == "110901"
        || scwin.sUserId == "050277" || scwin.sUserId == "121097" || scwin.sUserId == "281807" || scwin.sUserId == "111857" || scwin.sUserId == "050277" || scwin.sUserId == "131217" || scwin.sUserId == "170085"
        || scwin.sUserId == "223137" || scwin.sUserId == "223179" || scwin.sUserId == "233082" || scwin.sUserId == "233117"
    ) {
        acb_deleteState_1.setDisabled(false);
    } else {
        acb_deleteState_1.setDisabled(true);
    }
};

scwin.f_inputEquipmentContractGridAddrow = function() {
    let newRow = ds_SaveEquipmentContract.insertRow();
    let row = ds_LCCEList.getRowPosition();

    if (co_acb_posnClsCd_1.getValue() == "M") {
        ds_SaveEquipmentContract.setCellData(newRow, "ddMmClsCd", "1");
    }
    if (co_acb_posnClsCd_1.getValue() == "D") {
        ds_SaveEquipmentContract.setCellData(newRow, "ddMmClsCd", "2");
    }

    ds_SaveEquipmentContract.setCellData(newRow, "eqCd", ds_LCCEList.getCellData(row, "eqCd"));
    ds_SaveEquipmentContract.setCellData(newRow, "clntCd", ds_LCCEList.getCellData(row, "clntNo"));
    ds_SaveEquipmentContract.setCellData(newRow, "odrPrtDdStr", "0");
    ds_SaveEquipmentContract.setCellData(newRow, "lobranCd", ds_LCCEList.getCellData(row, "assgnLobranCd"));
};

scwin.f_AddRow = function() {
    let newRow = ds_ep_insurance.insertRow();
    let row = ds_LCCEList.getRowPosition();

    ds_ep_insurance.setCellData(newRow, "eqCd", ds_LCCEList.getCellData(row, "eqCd"));
    ds_ep_insurance.setCellData(newRow, "psnl1EntryYn", "1");
    ds_ep_insurance.setCellData(newRow, "psnl2EntryYn", "1");
    ds_ep_insurance.setCellData(newRow, "impsnlEntryYn", "1");
    ds_ep_insurance.setCellData(newRow, "selfEntryYn", "1");
    ds_ep_insurance.setCellData(newRow, "sfdmgEntryYn", "1");
};

scwin.f_AddRoweqcdCtrtHistory = function() {
    let newRow = ds_eqcdCtrtHistory.insertRow();
    let row = ds_LCCEList.getRowPosition();

    ds_eqcdCtrtHistory.setCellData(newRow, "eqCd", ds_LCCEList.getCellData(row, "eqCd"));
    ds_eqcdCtrtHistory.setCellData(newRow, "discrdYn", "0");
    ds_eqcdCtrtHistory.setCellData(newRow, "delYn", "0");
    ds_eqcdCtrtHistory.setCellData(newRow, "adjmCoreCls", "");
    ds_eqcdCtrtHistory.setCellData(newRow, "posnClsCd", "");
};

scwin.f_Update = function() {
    gr_EquipmentContractList.setReadOnly("grid", false);
    txt_em_vehclNm_1.setDisabled(true);
    co_lc_jumso_1.setDisabled(true);
    txt_vehclNo_2.setDisabled(true);
    txt_vehclNo_3.setDisabled(true);
    txt_vehclNo_4.setDisabled(true);

    acb_prsnInfoYn.setDisabled(true);
    txt_prsnInfoDtm.setDisabled(true);

    $c.gus.cfEnableObjects([b_cancel, btn_save]);
    $c.gus.cfDisableObjects([btn_new, btn_update]);

    if (scwin.sUserId == "101384" || scwin.sUserId == "080953" || scwin.sUserId == "051390" || scwin.sUserId == "origin" || scwin.sUserId == "herekjs" || scwin.sUserId == "hpark" || scwin.sUserId == "110901"
        || scwin.sUserId == "050277" || scwin.sUserId == "121097" || scwin.sUserId == "073294" || scwin.sUserId == "281807" || scwin.sUserId == "111857" || scwin.sUserId == "050277" || scwin.sUserId == "131217"
        || scwin.sUserId == "170085" || scwin.sUserId == "223137" || scwin.sUserId == "223179" || scwin.sUserId == "233082" || scwin.sUserId == "233117"
    ) {
        acb_deleteState_1.setDisabled(false);
    } else {
        acb_deleteState_1.setDisabled(true);
    }
};

scwin.fn_updateYn = async function() {
    scwin.updateYn = false;
    let row = ds_LCCEList.getRowPosition();

    let org_vehclShortCd = ds_LCCEList.getOrgCellData(row, "vehclShortCd");
    let org_clntNo = ds_LCCEList.getOrgCellData(row, "clntNo");
    let org_logisVehclDrvNm1 = ds_LCCEList.getOrgCellData(row, "logisVehclDrvNm1");
    let org_eqModelCd = ds_LCCEList.getOrgCellData(row, "eqModelCd");
    let org_wrkDstCd = ds_LCCEList.getOrgCellData(row, "wrkDstCd");
    let org_trsNo1 = ds_LCCEList.getOrgCellData(row, "trsNo1");
    let org_dtgNo = ds_LCCEList.getOrgCellData(row, "dtgNo");
    let org_logisHveqRepCopCoNo = ds_LCCEList.getOrgCellData(row, "logisHveqRepCopCoNo");
    let org_posnClsCd = ds_LCCEList.getOrgCellData(row, "posnClsCd");
    let org_maxShipwgtVol = ds_LCCEList.getOrgCellData(row, "maxShipwgtVol");
    let org_bondTransStDt = ds_LCCEList.getOrgCellData(row, "bondTransStDt");
    let org_bondTransEndDt = ds_LCCEList.getOrgCellData(row, "bondTransEndDt");
    let org_vehclOpentopblcYn = ds_LCCEList.getOrgCellData(row, "vehclOpentopblcYn");
    let org_dtgKnd = ds_LCCEList.getOrgCellData(row, "dtgKnd");

    let new_vehclShortCd = ds_LCCEList.getCellData(row, "vehclShortCd");
    let new_clntNo = ds_LCCEList.getCellData(row, "clntNo");
    let new_logisVehclDrvNm1 = ds_LCCEList.getCellData(row, "logisVehclDrvNm1");
    let new_eqModelCd = ds_LCCEList.getCellData(row, "eqModelCd");
    let new_wrkDstCd = ds_LCCEList.getCellData(row, "wrkDstCd");
    let new_trsNo1 = ds_LCCEList.getCellData(row, "trsNo1");
    let new_dtgNo = ds_LCCEList.getCellData(row, "dtgNo");
    let new_logisHveqRepCopCoNo = ds_LCCEList.getCellData(row, "logisHveqRepCopCoNo");
    let new_posnClsCd = ds_LCCEList.getCellData(row, "posnClsCd");
    let new_maxShipwgtVol = ds_LCCEList.getCellData(row, "maxShipwgtVol");
    let new_bondTransStDt = ds_LCCEList.getCellData(row, "bondTransStDt");
    let new_bondTransEndDt = ds_LCCEList.getCellData(row, "bondTransEndDt");
    let new_vehclOpentopblcYn = ds_LCCEList.getCellData(row, "vehclOpentopblcYn");
    let new_dtgKnd = ds_LCCEList.getCellData(row, "dtgKnd");

    if (org_vehclShortCd != new_vehclShortCd) { scwin.updateYn = true; }
    if (org_clntNo != new_clntNo) { scwin.updateYn = true; }
    if (org_logisVehclDrvNm1 != new_logisVehclDrvNm1) { scwin.updateYn = true; }
    if (org_eqModelCd != new_eqModelCd) { scwin.updateYn = true; }
    if (org_wrkDstCd != new_wrkDstCd) { scwin.updateYn = true; }
    if (org_trsNo1 != new_trsNo1) { scwin.updateYn = true; }
    if (org_dtgNo != new_dtgNo) { scwin.updateYn = true; }
    if (org_logisHveqRepCopCoNo != new_logisHveqRepCopCoNo) { scwin.updateYn = true; }
    if (org_posnClsCd != new_posnClsCd) { scwin.updateYn = true; }
    if (org_maxShipwgtVol != new_maxShipwgtVol) { scwin.updateYn = true; }
    if (org_bondTransStDt != new_bondTransStDt) { scwin.updateYn = true; }
    if (org_bondTransEndDt != new_bondTransEndDt) { scwin.updateYn = true; }
    if (org_vehclOpentopblcYn != new_vehclOpentopblcYn) { scwin.updateYn = true; }
    if (org_dtgKnd != new_dtgKnd) { scwin.updateYn = true; }

    if (ds_eqcdCtrtHistory.getUpdatedIndex().length > 0) { scwin.updateYn = true; }

    if (scwin.updateYn == true) {
        acb_deleteState_1.setValue("2");
    }
};

scwin.f_Save = async function(gubun) {
    scwin.eventYn = true;
    let kind_str1 = "";
    let row = ds_LCCEList.getRowPosition();
    let state_val = ds_LCCEList.getRowStatus(row);
    let carKndChk_val = "LV";

    kind_str1 = co_acb_posnClsCd_1.getValue();

    if (kind_str1 == "") {
        await $c.gus.cfAlertMsg("배정점소는 필수 입력 항목입니다.");
        co_acb_posnClsCd_1.setFocus();
        return;
    }

    if (txt_ed_reqMchtCd2_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["소속협력업체"]);
        return;
    }
    if (txt_ed_reqMchtCd1_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["정산협력업체"]);
        return;
    }
    if (txt_em_vehclNm_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량번호"]);
        txt_em_vehclNm_1.setFocus();
        return;
    }

    if (state_val == "U" && acb_deleteState_1.getValue() == "0") {
        await scwin.f_openPopUp(11, 'T');
        if (ds_LCCEList.getCellData(row, "workFlaga") == "N") {
            return;
        }
    }

    if (txt_vehclShortCd_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량단축번호"]);
        txt_vehclShortCd_1.setFocus();
        return;
    }
    if (txt_ed_eqModelCd_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["모델명"]);
        return;
    }
    if (txt_driver_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["차량기사"]);
        txt_driver_1.setFocus();
        return;
    }
    if (txt_driver_hptel_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["휴대전화"]);
        txt_driver_hptel_1.setFocus();
        return;
    }
    if (co_acb_posnClsCd_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["소유구분"]);
        co_acb_posnClsCd_1.setFocus();
        return;
    }
    if (co_lc_area1_1.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업권역"]);
        co_lc_area1_1.setFocus();
        return;
    }
    if (co_lc_workterm.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업구간"]);
        co_lc_workterm.setFocus();
        return;
    }
    if (acb_hwajong1Cd.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["선호화종1"]);
        acb_hwajong1Cd.setFocus();
        return;
    }

    if ((acb_dtgKnd.getValue() == "1" || acb_dtgKnd.getValue() == "2") && $c.gus.cfIsNull(txt_dtgNo.getValue())) {
        await $c.gus.cfAlertMsg("DTG번호를 입력해 주십시오.");
        txt_dtgNo.setFocus();
        return;
    }

    if (ica_boseFromDate.getValue() > ica_boseToDate.getValue()) {
        await $c.gus.cfAlertMsg("보세운송기간 " + MSG_CM_ERR_039);
        ica_boseFromDate.setFocus();
        return;
    }

    if (txt_lbsYn.getValue() == "1") {
        if ($c.gus.cfIsNull(txt_pdaNo.getValue())) {
            await $c.gus.cfAlertMsg("LBS관제차량인 경우 스마트폰번호는 필수입력항목입니다.");
            txt_pdaNo.setFocus();
            return false;
        }
    }

    if ($c.gus.cfIsNull(txt_pdaNo.getValue())) {
        acb_realPdaYn.setValue("0");
    }

    for (let i = 0; i < ds_SaveEquipmentContract.getRowCount(); i++) {
        if (ds_SaveEquipmentContract.getCellData(i, "ctrtStDt") == "") {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄의 계약시작일자는 필수 입력 항목입니다.");
            ds_SaveEquipmentContract.setRowPosition(i);
            gr_EquipmentContractList.setFocusedCell(i, "ctrtStDt");
            return;
        }
        if (ds_SaveEquipmentContract.getCellData(i, "ctrtEndDt") == "") {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄의 계약종료일은 필수 입력 항목입니다.");
            ds_SaveEquipmentContract.setRowPosition(i);
            gr_EquipmentContractList.setFocusedCell(i, "ctrtEndDt");
            return;
        }
        if (ds_SaveEquipmentContract.getCellData(i, "clntNo") == "") {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄의 협력업체는 필수 입력 항목입니다.");
            ds_SaveEquipmentContract.setRowPosition(i);
            gr_EquipmentContractList.setFocusedCell(i, "clntNo");
            return;
        }
        if (ds_SaveEquipmentContract.getCellData(i, "payCond") == "") {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄의 계약조건은 필수 입력 항목입니다.");
            ds_SaveEquipmentContract.setRowPosition(i);
            gr_EquipmentContractList.setFocusedCell(i, "payCond");
            return;
        }
        if (ds_SaveEquipmentContract.getCellData(i, "ctrtAmt") == "") {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄의 계약금액은 필수 입력 항목입니다.");
            ds_SaveEquipmentContract.setRowPosition(i);
            gr_EquipmentContractList.setFocusedCell(i, "ctrtAmt");
            return;
        }
    }

    let total_cnt = ds_SaveEquipmentContract.getRowCount();
    for (let i = 0; i < total_cnt; i++) {
        for (let j = i + 1; j < total_cnt; j++) {
            if (!(ds_SaveEquipmentContract.getCellData(i, "ctrtStDt") > ds_SaveEquipmentContract.getCellData(j, "ctrtEndDt") || ds_SaveEquipmentContract.getCellData(i, "ctrtEndDt") < ds_SaveEquipmentContract.getCellData(j, "ctrtStDt"))) {
                await $c.gus.cfAlertMsg((j + 1) + " 번째줄의 계약기간이 중복되었습니다.");
                ds_SaveEquipmentContract.setRowPosition(j);
                gr_EquipmentContractList.setFocusedCell(j, "ctrtEndDt");
                return;
            }
        }
    }

    for (let i = 0; i < ds_ep_insurance.getRowCount(); i++) {
        if (!$c.gus.cfValidateValue(ds_ep_insurance.getCellData(i, "insrStDt"), "date=YYYYMMDD")) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["보험시작일자"]);
            return;
        }
        if (!$c.gus.cfValidateValue(ds_ep_insurance.getCellData(i, "insrEndDt"), "date=YYYYMMDD")) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["보험종료일자"]);
            return;
        }
        if (!$c.gus.cfValidateValue(ds_ep_insurance.getCellData(i, "insrEndDt"), "minDate=" + ds_ep_insurance.getCellData(i, "insrStDt"))) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            return;
        }
    }

    if (txt_ed_reqMchtCd2_1.getValue() != txt_ed_reqMchtCd1_1.getValue()) {
        await $c.win.alert("소속협력업체코드 [ " + txt_ed_reqMchtCd2_1.getValue() + " ] 는 정산협력업체코드 [ " + txt_ed_reqMchtCd1_1.getValue()
            + " ] 와 다릅니다.\n 정산협력업체코드는 실적발생시 통합매입의 매입거래처로 생성됩니다. \n 정산협력업체코드 [ "
            + txt_ed_reqMchtCd1_1.getValue() + " ]로 매입정보를 생성하는 것이 맞으시면 계속 진행하시고,\n 틀리면 수정하여 주십시오.");
    }

    if (!(await scwin.f_CheckEqcdCtrtHistory())) {
        return;
    }

    scwin.fn_updateYn();

    let param_str = "";
    if (gubun) {
        param_str = "carKndCd=" + carKndChk_val + "&eqCdModify=" + ds_LCCEList.getCellData(row, "eqCd") + "&deleteKndCd=B";
        sbm_SaveCooperationCompanyContractEquipment.action = "/tn.cs.vehclmgnt.SaveDirecMgntVehclCMD.do?" + param_str;
        await $c.sbm.execute(sbm_SaveCooperationCompanyContractEquipment);
    } else {
        let chk = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk == true) {
            param_str = "carKndCd=" + carKndChk_val + "&eqCdModify=" + ds_LCCEList.getCellData(row, "eqCd") + "&deleteKndCd=B";
            sbm_SaveCooperationCompanyContractEquipment.action = "/tn.cs.vehclmgnt.SaveDirecMgntVehclCMD.do?" + param_str;
            await $c.sbm.execute(sbm_SaveCooperationCompanyContractEquipment);
        }
    }

    scwin.oldCurPos = ds_LCCEList.getRowPosition();
};

scwin.f_CheckEqcdCtrtHistory = async function() {
    let row = ds_LCCEList.getRowPosition();
    let hRow = ds_eqcdCtrtHistory.getRowPosition();
    if (hRow >= 0) {
        ds_eqcdCtrtHistory.setCellData(hRow, "eqCd", ds_LCCEList.getCellData(row, "eqCd"));
    }

    if (!(await $c.gus.cfValidate([gr_EquipmentContractList]))) {
        return false;
    }

    let total_cnt = ds_eqcdCtrtHistory.getRowCount();
    for (let i = 0; i < total_cnt; i++) {
        for (let j = i + 1; j < total_cnt; j++) {
            if (!(ds_eqcdCtrtHistory.getCellData(i, "ctrtStDt") > ds_eqcdCtrtHistory.getCellData(j, "ctrtEndDt") || ds_eqcdCtrtHistory.getCellData(i, "ctrtEndDt") < ds_eqcdCtrtHistory.getCellData(j, "ctrtStDt"))) {
                await $c.gus.cfAlertMsg((j + 1) + " 번째줄의 계약기간이 중복되었습니다.");
                ds_SaveEquipmentContract.setRowPosition(j);
                gr_EquipmentContractList.setFocusedCell(j, "ctrtEndDt");
                return false;
            }
        }

        if (ds_eqcdCtrtHistory.getCellData(i, "discrdYn") == "1") {
            if (ds_eqcdCtrtHistory.getCellData(i, "discrdRsn") == "") {
                await $c.gus.cfAlertMsg((i + 1) + " 번째줄 불일치사유를 작성 해 주세요");
                return false;
            }
        }

        let rowStatus = ds_eqcdCtrtHistory.getRowStatus(i);
        if (ds_eqcdCtrtHistory.getCellData(i, "adjmCoreCls") == ""
            && (rowStatus == "C" || rowStatus == "U")
            && (co_acb_posnClsCd_1.getValue() == "Y" || co_acb_posnClsCd_1.getValue() == "Z")) {
            await $c.gus.cfAlertMsg((i + 1) + " 번째줄 정산주체를 선택 해 주세요");
            gr_EquipmentContractList.setFocusedCell(i, "adjmCoreCls");
            return false;
        }
    }

    return true;
};

scwin.f_Cancel = function() {
    ds_LCCEList.undoAll();
    ds_SaveEquipmentContract.undoAll();
    ds_ep_insurance.undoAll();

    if (ds_LCCEList.getRowCount() == 0) {
        $c.gus.cfEnableObjects([btn_new]);
        $c.gus.cfDisableObjects([btn_update, b_cancel, btn_save]);
    } else {
        $c.gus.cfEnableObjects([btn_new, btn_update]);
        $c.gus.cfDisableObjects([b_cancel, btn_save]);
    }

    gr_EquipmentContractList.setReadOnly("grid", true);
};

