scwin.f_CheckVehclNo = async function() {
    let checkFlag = true;
    let row = ds_LCCEList.getRowPosition();
    let length = ds_LCCEList.getCellData(row, "vehclNo1").length;

    for (let i = 0; i < length; i++) {
        let ch = ds_LCCEList.getCellData(row, "vehclNo1").charAt(i).toUpperCase();
        let retCode = ds_LCCEList.getCellData(row, "vehclNo1").charCodeAt(i);
        retCode = parseInt(retCode);
        if ((ch < "0" || ch > "9") && (ch < "A" || ch > "Z") && ((retCode > 255) || (retCode < 0))) {
            checkFlag = true;
        } else {
            checkFlag = false;
            return checkFlag;
        }
    }

    length = ds_LCCEList.getCellData(row, "vehclNo2").length;
    for (let i = 0; i < length; i++) {
        let ch = ds_LCCEList.getCellData(row, "vehclNo2").charAt(i).toUpperCase();
        let retCode = ds_LCCEList.getCellData(row, "vehclNo2").charCodeAt(i);
        retCode = parseInt(retCode);
        if (ch >= "0" && ch <= "9") {
            checkFlag = true;
        } else {
            checkFlag = false;
            return checkFlag;
        }
    }

    length = ds_LCCEList.getCellData(row, "vehclNo3").length;
    for (let i = 0; i < length; i++) {
        let ch = ds_LCCEList.getCellData(row, "vehclNo3").charAt(i).toUpperCase();
        let retCode = ds_LCCEList.getCellData(row, "vehclNo3").charCodeAt(i);
        retCode = parseInt(retCode);
        if ((ch < "0" || ch > "9") && (ch < "A" || ch > "Z") && ((retCode > 255) || (retCode < 0))) {
            checkFlag = true;
        } else {
            checkFlag = false;
            return checkFlag;
        }
    }

    length = ds_LCCEList.getCellData(row, "vehclNo4").length;
    for (let i = 0; i < length; i++) {
        let ch = ds_LCCEList.getCellData(row, "vehclNo4").charAt(i).toUpperCase();
        let retCode = ds_LCCEList.getCellData(row, "vehclNo4").charCodeAt(i);
        retCode = parseInt(retCode);
        if (ch >= "0" && ch <= "9") {
            checkFlag = true;
        } else {
            checkFlag = false;
            return checkFlag;
        }
    }

    return checkFlag;
};

