scwin.f_dateChk = async function(BaseRow, BaseColid) {
    if (ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtStDt") > ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtEndDt")) {
        if (BaseColid == "ctrtStDt" && ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtEndDt") != "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["계약시작일자"]);
            ds_SaveEquipmentContract.setCellData(BaseRow, "ctrtStDt", "");
        }
        if (BaseColid == "ctrtEndDt" && ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtStDt") != "" && ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtEndDt") != "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["계약종료일자"]);
            ds_SaveEquipmentContract.setCellData(BaseRow, "ctrtEndDt", "");
        }
    }

    if (BaseColid == "ctrtEndDt" && ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtEndDt") < scwin.dateStr && ds_SaveEquipmentContract.getCellData(BaseRow, "ctrtEndDt") != "") {
        await $c.gus.cfAlertMsg("계약종료일자가 현재일보다 이전일자는 등록되지  않습니다.");
        ds_SaveEquipmentContract.setCellData(BaseRow, "ctrtEndDt", "");
    }
};

scwin.f_direcMgntYn = async function() {
};

scwin.f_SaveECDelRow = async function() {
    let ecRow = ds_SaveEquipmentContract.getRowPosition();
    if (ds_SaveEquipmentContract.getRowStatus(ecRow) == "C") {
        ds_SaveEquipmentContract.removeRow(ecRow);
        return;
    }

    let row = ds_LCCEList.getRowPosition();
    let tempStr = "";
    if (ds_LCCEList.getCellData(row, "posnClsCd") == "W" || ds_LCCEList.getCellData(row, "posnClsCd") == "J") {
        if (ds_LCCEList.getCellData(row, "posnClsCd") == "W") {
            tempStr = "위수탁";
        }
        if (ds_LCCEList.getCellData(row, "posnClsCd") == "J") {
            tempStr = "직영";
        }
        await $c.gus.cfAlertMsg("이 화면에서 " + tempStr + "는 수정 또는 삭제 할수 없습니다. 공통장비관리 화면에서 처리하세요");
        return;
    }

    if (ds_SaveEquipmentContract.getCellData(ecRow, "ctrtEndDt") < scwin.dateStr) {
        await $c.gus.cfAlertMsg("계약종료일자가 현재일보다 이전일자는 삭제하지  않습니다.");
    } else {
        ds_SaveEquipmentContract.removeRow(ecRow);
    }
};

