scwin.f_LCCEListOnclick = async function(row) {
    let carKndChk_val = "LV";

    if (ds_LCCEList.getRowCount() == 0) {
        $c.gus.cfEnableObjects([btn_new]);
        $c.gus.cfDisableObjects([btn_update, b_cancel, btn_save, btn_owner]);
    } else {
        $c.gus.cfEnableObjects([btn_new, btn_update]);
        $c.gus.cfDisableObjects([b_cancel, btn_save]);
    }

    gr_EquipmentContractList.setReadOnly("grid", true);

    if (ds_LCCEList.getCellData(row, "eqCd") != "") {
        dma_QueryCondition2.set("clntCd", ds_LCCEList.getCellData(row, "clntNo"));
        dma_QueryCondition2.set("eqCd", ds_LCCEList.getCellData(row, "eqCd"));
        ds_SaveEquipmentContract.removeAll();
        await $c.sbm.execute(sbm_RetrieveCooperationContract);

        ds_ep_insurance.removeAll();
        sbm_insurance.action = "/tn.cs.vehclmgnt.RetrieveEqInsrCMD.do?equipmentNumber=" + ds_LCCEList.getCellData(row, "eqCd");
        await $c.sbm.execute(sbm_insurance);

        await scwin.f_RetrieveEqcdCtrtHistory();
    }

    scwin.f_districtSearchKind();
};

