scwin.f_fileSet = async function(row, data) {
    let argObject = {
        fileName: ds_eqcdCtrtHistory.getCellData(row, "fileNm"),
        filePath: ds_eqcdCtrtHistory.getCellData(row, "filePath")
    };

    let resultList = await $c.win.openPopup("/ui/tn/cs/clntmgnt/tn_200_01_01p.xml", {
        width: 650,
        height: 400,
        modal: true,
        data: argObject
    });

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            ds_eqcdCtrtHistory.setCellData(row, "fileNm", resultList[1]);
            ds_eqcdCtrtHistory.setCellData(row, "filePath", resultList[0]);
            ds_eqcdCtrtHistory.setCellData(row, "fileSiz", resultList[2]);
        }
    }
};

scwin.f_Download = async function() {
    let row = ds_eqcdCtrtHistory.getRowPosition();

    if (row < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["첨부파일 행"]);
        return;
    }

    let fileName = ds_eqcdCtrtHistory.getCellData(row, "fileNm");
    let filePath = ds_eqcdCtrtHistory.getCellData(row, "filePath");

    if (filePath.trim().length == 0) {
        await $c.win.alert("선택하신 " + (row + 1) + "행 해당 항목에 파일이 등록되어 있지 않습니다.");
    } else {
        if (filePath.indexOf(".") > 0) {
            fileName += filePath.substring(filePath.indexOf("."), filePath.indexOf(".") + 4);
            $c.gus.cfDownloadFile(fileName, filePath);
        }
    }
};

