scwin.ds_LCCEList_onrowpositionchange = async function(info) {
    let row = info.row;
    if (!scwin.eventYn) return;

    let ChgCount = 0;
    let ChgRow = 0;

    for (let i = 0; i < ds_LCCEList.getRowCount(); i++) {
        let CurRowStatus = ds_LCCEList.getRowStatus(i);
        if (CurRowStatus == "C" || CurRowStatus == "U") {
            ChgCount++;
            ChgRow = i;
        }
    }

    if ((ChgCount > 0 && row != ChgRow) || ds_ep_insurance.getUpdatedIndex().length > 0) {
        let chk = await $c.win.confirm("차량정보가 변경되었습니다. 저장하시겠습니까?");
        if (chk) {
            scwin.eventYn = false;
            ds_LCCEList.setRowPosition(ChgRow);
            scwin.f_Save(true);
            return;
        } else {
            scwin.f_Cancel();
        }
    }

    scwin.f_LCCEListOnclick(row);
};

