scwin.gr_eqcdCtrtHistory_oneditend = async function(rowIndex, columnIndex, columnId, value, oldValue) {
    let row = rowIndex;
    let colid = columnId;
    if (colid == "ctrtEndDt") {
        let startDate = ds_eqcdCtrtHistory.getCellData(row, "ctrtStDt");
        let endDate = ds_eqcdCtrtHistory.getCellData(row, "ctrtEndDt");
        if (!$c.gus.cfIsAfterDate(startDate, endDate)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ds_eqcdCtrtHistory.setCellData(row, "ctrtStDt", "");
            ds_eqcdCtrtHistory.setCellData(row, "ctrtEndDt", "");
        }
    }

    if (colid == "drvNm" || colid == "ctrtPicNm" || colid == "accntPicNm") {
        let drvNm = ds_eqcdCtrtHistory.getCellData(row, "drvNm");
        let ctrtPicNm = ds_eqcdCtrtHistory.getCellData(row, "ctrtPicNm");
        let accntPicNm = ds_eqcdCtrtHistory.getCellData(row, "accntPicNm");
        if (drvNm != accntPicNm || ctrtPicNm != accntPicNm) {
            ds_eqcdCtrtHistory.setCellData(row, "discrdYn", "1");
        } else {
            ds_eqcdCtrtHistory.setCellData(row, "discrdYn", "0");
        }
    }
};

